function cleanRole(r) {
  let s = String(r==null?'🆕 New':r);
  // Force-fix: jeder role-string der 'admin' enthält → IMMER '🛡️ Admin' (egal welche corruption)
  if (/admin/i.test(s)) return '🛡️ Admin';
  // Sonst: gear-emoji + leading-question-marks cleanup
  s = s.replace(/⚙️?/g,'🛡️');
  s = s.replace(/^[\?\u{FFFD}]{1,4}\s*/u,'🛡️ ');
  return s;
}
// Sicherer URL-Check: nur http(s)-Links erlaubt, kein javascript:/data:/vbscript:.
function safeUrl(u) { const s = String(u||'').trim(); return /^https?:\/\//i.test(s) ? s : ''; }

// 👑 Top-3 User mit höchstem XP (ohne Admins, Subs, System).
// Top1 = gold, Top2 = silber, Top3 = bronze — wird ÜBERALL angezeigt wo Username gerendert wird.
function getTop3Uids(d, adminIds=[]) {
    const ranked = Object.entries(d?.users || {})
        .filter(([uid, u]) => u && !u.parent_uid && !u.isSystem && uid !== 'creatorboost' && !adminIds.includes(Number(uid)))
        .sort(([,a],[,b]) => (b.xp||0) - (a.xp||0));
    return {
        top1: ranked[0]?.[0] ? String(ranked[0][0]) : '',
        top2: ranked[1]?.[0] ? String(ranked[1][0]) : '',
        top3: ranked[2]?.[0] ? String(ranked[2][0]) : '',
    };
}
// Backwards-compat: getTop1Uid liefert nur den Top-1 Uid als String.
function getTop1Uid(d, adminIds=[]) { return getTop3Uids(d, adminIds).top1; }
// rankOf(uid, top3) → 1, 2, 3 oder 0 (kein Crown).
function rankOf(uid, top3) {
    if (!top3) return 0;
    const s = String(uid);
    if (top3.top1 && s === top3.top1) return 1;
    if (top3.top2 && s === top3.top2) return 2;
    if (top3.top3 && s === top3.top3) return 3;
    return 0;
}
// Text-Variante: nur Top-1 bekommt 👑 prefix (CSS-Filter funktionieren nicht in Plain-Text-Contexts
// wie escTxt-escapten Notification-Names oder 'Gefällt X, Y'-Text).
function makeCrown(top1Uid) {
    const top1 = (top1Uid && typeof top1Uid === 'object') ? top1Uid.top1 : top1Uid;
    return (uid) => (top1 && String(uid) === top1) ? '👑 ' : '';
}
// Visuelle Krone als HTML-Overlay über dem Avatar (für Stories/Posts/Profil).
// Container muss position:relative sein. size: '' (default ~18px), 'sm' (~13px), 'xs' (~10px).
// top3 kann ein Objekt {top1, top2, top3} oder ein String (= Top-1 nur) sein.
function makeCrownOverlay(top3) {
    const t = (top3 && typeof top3 === 'object') ? top3 : { top1: top3 || '', top2: '', top3: '' };
    return (uid, size='') => {
        const r = rankOf(uid, t);
        if (!r) return '';
        const baseCls = size==='sm' ? 'crown-float-sm' : size==='xs' ? 'crown-float-xs' : 'crown-float';
        const rankCls = r===1 ? '' : (r===2 ? ' rank-silver' : ' rank-bronze');
        return '<div class="' + baseCls + rankCls + '">👑</div>';
    };
}

const ONLINE_WINDOW_MS = 60000;
function isUidOnline(uid) {
    const u = String(uid), now = Date.now();
    for (const s of sessions.values()) {
        if (String(s.uid) === u && (now - (s.lastSeen||0)) < ONLINE_WINDOW_MS) return true;
    }
    return false;
}
function getOnlineUids() {
    const now = Date.now(), out = new Set();
    for (const s of sessions.values()) {
        if ((now - (s.lastSeen||0)) < ONLINE_WINDOW_MS) out.add(String(s.uid));
    }
    return out;
}

function verifyTelegramLogin(data) {
    try {
        const { hash, ...rest } = data;
        const secret = crypto.createHash('sha256').update(BOT_TOKEN).digest();
        const str = Object.keys(rest).sort().map(k=>`${k}=${rest[k]}`).join('\n');
        const hmac = crypto.createHmac('sha256', secret).update(str).digest('hex');
        const age = Date.now()/1000 - Number(rest.auth_date||0);
        return hmac === hash && age < 86400;
    } catch(e) { return false; }
}

let _dataCache = null;
let _dataCacheTime = 0;
const DATA_CACHE_TTL = 60000; // 60 seconds

async function fetchBotRaw(path) {
    return new Promise(resolve => {
        const fullUrl = MAINBOT_URL + path;
        if (!fullUrl.startsWith('http')) return resolve(null);
        const lib = fullUrl.startsWith('https')?https:http;
        const req = lib.get(fullUrl, {headers:{'x-bridge-secret':BRIDGE_SECRET}}, res => {
            let data=''; res.on('data',c=>data+=c); res.on('end',()=>{
                try { resolve(JSON.parse(data)); } catch(e){ resolve(null); }
            });
        });
        req.on('error',()=>resolve(null)); req.setTimeout(3000,()=>{req.destroy();resolve(null);});
    });
}

let _refreshInFlight = null;
function refreshDataCache() {
    if (_refreshInFlight) return _refreshInFlight;
    _refreshInFlight = (async () => {
        try {
            const parsed = await fetchBotRaw('/data');
            if (parsed) { _dataCache = parsed; _dataCacheTime = Date.now(); }
        } catch(e) {}
        finally { _refreshInFlight = null; }
    })();
    return _refreshInFlight;
}

async function fetchBot(path) {
    if (path === '/data') {
        const now = Date.now();
        if (_dataCache) {
            // Return cached data immediately (stale-while-revalidate)
            if ((now - _dataCacheTime) > DATA_CACHE_TTL) refreshDataCache();
            return _dataCache;
        }
        // No cache yet - must wait
        await refreshDataCache();
        return _dataCache;
    }
    return fetchBotRaw(path);
}

// Pre-warm cache on startup and refresh every 45 seconds
setInterval(refreshDataCache, 45000);

async function postBot(path, body) {
    const result = await new Promise(resolve => {
        const fullUrl = MAINBOT_URL + path;
        if (!fullUrl.startsWith('http')) return resolve(null);
        const lib = fullUrl.startsWith('https')?https:http;
        const data = JSON.stringify(body);
        const u = new url.URL(fullUrl);
        const opts = {hostname:u.hostname,path:u.pathname+u.search,method:'POST',headers:{'Content-Type':'application/json','x-bridge-secret':BRIDGE_SECRET,'Content-Length':Buffer.byteLength(data)}};
        const req = lib.request(opts, res=>{
            let buf='';
            res.on('data',c=>buf+=c);
            res.on('end',()=>{
                // Vorher fallback {ok:true} — bei Bot-Crash/empty-response sah App
                // jeden Call als Erfolg. Jetzt: null wie fetchBotRaw bei Parse-Fehler.
                try { resolve(JSON.parse(buf)); } catch(e) { resolve(null); }
            });
        });
        req.on('error',()=>resolve(null));
        // 5-Sek Timeout (vorher unbounded — Bot-Hang würde App-Request blockieren)
        req.setTimeout(5000, () => { req.destroy(); resolve(null); });
        req.write(data); req.end();
    });
    _dataCache = null; _dataCacheTime = 0;
    refreshDataCache().catch(()=>{});
    return result;
}

// ── ZEIT-CRON ──────────────────────────────────────────────────────────────
// Sonntag 20:00 (Berlin TZ, schon global gesetzt) triggert Wochen-Gewinnspiel
// + Mindset-Stories-Pick im Mainbot. Mainbot kümmert sich weiterhin selbst um
// Daily/Wochen-Reset (intern). einmalig() Pattern verhindert Doppel-Trigger
// innerhalb einer Minute.
const _appCronSeen = {};
async function appCronTick() {
    try {
        const jetzt = new Date();
        const h = jetzt.getHours();
        const m = jetzt.getMinutes();
        const wochentag = jetzt.getDay();
        const tagStr = jetzt.toDateString();
        const einmalig = (key, fn) => {
            const fullKey = `${key}_${h}:${m}_${tagStr}`;
            if (_appCronSeen[fullKey]) return;
            _appCronSeen[fullKey] = true;
            return fn();
        };
        if (wochentag === 0 && h === 20 && m === 0) {
            einmalig('wochenGewinnspiel', async () => {
                console.log('🎰 [Cron] Trigger Wochen-Gewinnspiel → Mainbot');
                const r = await postBot('/run-wochen-gewinnspiel-api', {});
                console.log('🎰 [Cron] Mainbot Response:', r ? JSON.stringify(r) : 'null');
            });
            einmalig('mindsetPick', async () => {
                console.log('📖 [Cron] Trigger Mindset-Stories-Pick → Mainbot');
                const r = await postBot('/run-mindset-pick-api', {});
                console.log('📖 [Cron] Mainbot Response:', r ? JSON.stringify(r) : 'null');
            });
        }
        // Tageswechsel: alte einmalig-Keys aufräumen, damit der Speicher nicht wächst.
        for (const key of Object.keys(_appCronSeen)) { if (!key.endsWith(tagStr)) delete _appCronSeen[key]; }
    } catch (e) { console.log('appCronTick Fehler:', e.message); }
}
setInterval(appCronTick, 60000);

const PARSE_BODY_MAX = 1024 * 1024; // 1MB cap; uploads use readBody with explicit limits
function parseBody(req) {
    return new Promise(resolve => {
        let body=''; let abort=false;
        req.on('data',c=>{
            if (abort) return;
            body += c;
            if (body.length > PARSE_BODY_MAX) { abort = true; req.destroy(); resolve({}); }
        });
        req.on('end',()=>{
            if (abort) return;
            try{resolve(JSON.parse(body));}catch(e){
                const p={};body.split('&').forEach(kv=>{const[k,v]=kv.split('=');if(k)p[decodeURIComponent(k)]=decodeURIComponent((v||'').replace(/\+/g,' '));});resolve(p);
            }
        });
        req.on('error', ()=>{ if(!abort){abort=true;resolve({});} });
    });
}

function xpNext(xp) {
    if(xp<50)return{ziel:'📘',fehlend:50-xp,pct:Math.round(xp/50*100)};
    if(xp<500)return{ziel:'⬆️',fehlend:500-xp,pct:Math.round((xp-50)/450*100)};
    if(xp<1000)return{ziel:'🏅',fehlend:1000-xp,pct:Math.round((xp-500)/500*100)};
    if(xp<5000)return{ziel:'👑',fehlend:5000-xp,pct:Math.round((xp-1000)/4000*100)};
    if(xp<10000)return{ziel:'🌟',fehlend:10000-xp,pct:Math.round((xp-5000)/5000*100)};
    return null;
}

function badgeGradient(role) {
    if(role?.includes('Elite+')) return 'linear-gradient(135deg,#00b4db,#a855f7,#f59e0b)';
    if(role?.includes('Elite')) return 'linear-gradient(135deg,#f59e0b,#ef4444)';
    if(role?.includes('Erfahrener')) return 'linear-gradient(135deg,#8b5cf6,#3b82f6)';
    if(role?.includes('Aufsteiger')) return 'linear-gradient(135deg,#3b82f6,#06b6d4)';
    if(role?.includes('Anfänger')) return 'linear-gradient(135deg,#10b981,#3b82f6)';
    return 'linear-gradient(135deg,#64748b,#94a3b8)';
}

const _bildCache = new Map();
const _BILD_CACHE_TTL = 120000;       // 2 min Daten-TTL (bisherig)
const _BILD_CACHE_MAX = 200;          // hartes Limit Einträge — verhindert unbounded growth
// Cache-Cleanup alle 5 Min: entferne abgelaufene Einträge + erzwinge Max-Größe.
setInterval(() => {
    const now = Date.now();
    for (const [k, v] of _bildCache.entries()) {
        if (now - (v?.ts || 0) > _BILD_CACHE_TTL * 5) _bildCache.delete(k);
    }
    if (_bildCache.size > _BILD_CACHE_MAX) {
        // Älteste zuerst (Map insertion-order)
        const overflow = _bildCache.size - _BILD_CACHE_MAX;
        const it = _bildCache.keys();
        for (let i = 0; i < overflow; i++) _bildCache.delete(it.next().value);
    }
}, 5 * 60 * 1000);

function ladeBild(uid, type) {
    // CreatorBoost-System-User: gebundeltes Avatar aus Repo.
    if (uid === 'creatorboost' && type === 'profilepic') return 'bundled';
    const key = uid + '_' + type;
    const hit = _bildCache.get(key);
    if (hit !== undefined && Date.now() - hit.ts < _BILD_CACHE_TTL) return hit.v;
    let v = null;
    try {
        const f = DATA_DIR + '/bild_' + uid + '_' + type + '.txt';
        if (fs.existsSync(f)) v = fs.readFileSync(f, 'utf8');
    } catch(e) {}
    _bildCache.set(key, {v, ts: Date.now()});
    return v;
}

function ladeProjectBild(uid, projectId) {
    try {
        const f = DATA_DIR + '/bild_' + uid + '_proj_' + projectId + '.txt';
        if (fs.existsSync(f)) return fs.readFileSync(f, 'utf8');
    } catch(e) {}
    return null;
}

function ladeProjectDoc(uid, projectId) {
    try {
        const f = DATA_DIR + '/doc_' + uid + '_proj_' + projectId + '.txt';
        if (fs.existsSync(f)) return fs.readFileSync(f, 'utf8');
    } catch(e) {}
    return null;
}

function ladePinnedLink(uid) {
    try {
        const f = DATA_DIR + '/pinnedlink_' + uid + '.txt';
        if (fs.existsSync(f)) return fs.readFileSync(f, 'utf8').trim();
    } catch(e) {}
    return null;
}

