  <div style="font-size:10px;font-weight:700;color:${tierColor};letter-spacing:1px;margin-bottom:8px">${tier==='Bronze'?'🥉':tier==='Silber'?'🥈':'🥇'} ${tier} — 💎 ${tierItems[0].price}</div>
